        IntroTemplate(id: .tip1, label: "Tip 1: Genel", html: "<style type=\"text/css\">.cag-info-row{\n\n    display:flex;\n\n    gap:10px;\n\n    margin-top:16px;\n\n    margin-bottom:8px;\n\n    font-family:\"Inter\",sans-serif;\n\n}\n\n.cag-info-item{\n\n    flex:1 1 0;\n\n    border:1px solid #e5e5e5;\n\n    border-radius:8px;\n\n    padding:10px 12px;\n\n    display:flex;\n\n    align-items:flex-start;\n\n    gap:8px;\n\n}\n\n/* hafif renkli arka planlar */\n\n.cag-info-item.kargo{\n\n    background:#f2fbf5;\n\n    border-color:#d5f0dc;\n\n}\n\n.cag-info-item.taksit{\n\n    background:#f2f7ff;\n\n    border-color:#d7e3ff;\n\n}\n\n.cag-info-item.indirim{\n\n    background:#fff7ef;\n\n    border-color:#ffe1c4;\n\n}\n\n.cag-info-icon{\n\n    width:26px;\n\n    height:26px;\n\n    flex:0 0 26px;\n\n    display:flex;\n\n    align-items:center;\n\n    justify-content:center;\n\n}\n\n.cag-info-icon img{\n\n    width:22px;\n\n    height:22px;\n\n    display:block;\n\n}\n\n.cag-info-text{\n\n    line-height:1.25;\n\n}\n\n.cag-info-title{\n\n    font-size:13px;\n\n    font-weight:600;\n\n    color:#111;\n\n    margin-bottom:2px;\n\n}\n\n.cag-info-desc{\n\n    font-size:12px;\n\n    color:#555;\n\n}\n\n\n\n@media (max-width:600px){\n\n    .cag-info-row{\n\n        flex-direction:column;\n\n    }\n\n}\n\n\n\n/* Özel ölçü kutusu */\n\n.cag-ozel-box{\n\n    border:1px solid #e5e5e5;\n\n    background:#fafafa;\n\n    border-radius:8px;\n\n    padding:12px 14px;\n\n    font-family:\"Inter\",sans-serif;\n\n    line-height:1.4;\n\n    margin-top:8px;\n\n}\n\n.cag-ozel-head{\n\n    font-size:14px;\n\n    font-weight:600;\n\n    color:#111;\n\n    margin:0 0 8px 0;\n\n    display:flex;\n\n    align-items:center;\n\n    gap:6px;\n\n}\n\n.cag-ozel-head-icon{\n\n    display:inline-flex;\n\n    align-items:center;\n\n    justify-content:center;\n\n    width:16px; height:16px;\n\n}\n\n.cag-ozel-head-icon img{\n\n    width:16px; height:16px; display:block;\n\n}\n\n.cag-ozel-text{\n\n    font-size:13px;\n\n    color:#444;\n\n    margin:0 0 10px 0;\n\n    line-height:1.5;\n\n}\n\n.cag-ozel-actions{\n\n    display:grid;\n\n    grid-template-columns:repeat(2, minmax(0,1fr));\n\n    gap:8px;\n\n}\n\n.cag-btn{\n\n    display:inline-flex;\n\n    align-items:center;\n\n    justify-content:center;\n\n    gap:8px;\n\n    border-radius:6px;\n\n    font-size:13px;\n\n    font-weight:600;\n\n    padding:9px 10px;\n\n    text-align:center;\n\n    border:1px solid transparent;\n\n    white-space:normal;\n\n    word-break:break-word;\n\n}\n\n.cag-btn-primary{ background:#000; color:#fff; border-color:#000; }\n\n.cag-btn-outline{ background:#fff; color:#000; border-color:#000; }\n\n\n\n/* Ortak hover rengi - daha koyu gri */\n\n.cag-btn-primary:hover,\n\n.cag-btn-outline:hover{\n\n    background:#d6d6d6;\n\n    border-color:#d6d6d6;\n\n    color:#000;\n\n    opacity:1;\n\n}\n\n\n\n/* WhatsApp ikonu span'i */\n\n.cag-btn-icon-whatsapp{\n\n    width:16px;\n\n    height:16px;\n\n    display:inline-block;\n\n    background-image:url(\"https://static.ticimax.cloud/72848/uploads/images/web-images-for-pages/whatsapp-white.svg\") !important;\n\n    background-position:center;\n\n    background-repeat:no-repeat;\n\n    background-size:16px 16px;\n\n}\n\n\n\n@media (max-width:480px){\n\n    .cag-ozel-actions{ gap:6px; }\n\n}\n\n</style>\n\n<!-- BİLGİ KUTULARI -->\n\n<div class=\"cag-info-row\">\n\n<div class=\"cag-info-item kargo\">\n\n<div class=\"cag-info-icon\"><img alt=\"Ücretsiz kargo\" src=\"https://static.ticimax.cloud/72848/uploads/images/web-images-for-pages/delivery-truck-speed-icon.svg\" /></div>\n\n\n\n<div class=\"cag-info-text\">\n\n<div class=\"cag-info-title\">Ücretsiz Kargo</div>\n\n\n\n<div class=\"cag-info-desc\">Tüm ürünlerde geçerlidir.</div>\n\n</div>\n\n</div>\n\n\n\n<div class=\"cag-info-item taksit\">\n\n<div class=\"cag-info-icon\"><img alt=\"Taksit\" src=\"https://static.ticimax.cloud/72848/uploads/images/web-images-for-pages/wallet-icon.svg\" /></div>\n\n\n\n<div class=\"cag-info-text\">\n\n<div class=\"cag-info-title\">Peşin Fiyatına 3 Taksit</div>\n\n\n\n<div class=\"cag-info-desc\">Anlaşmalı kartlara.</div>\n\n</div>\n\n</div>\n\n\n\n<div class=\"cag-info-item indirim\">\n\n<div class=\"cag-info-icon\"><img alt=\"İndirim\" src=\"https://static.ticimax.cloud/72848/uploads/images/web-images-for-pages/percent-discount-icon.svg\" /></div>\n\n\n\n<div class=\"cag-info-text\">\n\n<div class=\"cag-info-title\">İlk Alışverişine %10 İndirim</div>\n\n\n\n<div class=\"cag-info-desc\">Üye ol, sepette indirim kazan!</div>\n\n</div>\n\n</div>\n\n</div>\n\n<!-- ÖZEL ÖLÇÜ BLOĞU -->\n\n\n\n<div class=\"cag-ozel-box\">\n\n<div class=\"cag-ozel-head\"><span class=\"cag-ozel-head-icon\"> <img alt=\"Özel kesim\" src=\"https://static.ticimax.cloud/72848/uploads/images/web-images-for-pages/cut.svg\" /> </span> <span>Özel Ölçü Sipariş</span></div>\n\n\n\n<p class=\"cag-ozel-text\">Bazı modeller yalnızca standart ölçülerdedir. Uygun serilerimizde ise halınızı istediğiniz ebatta hazırlayabiliyoruz.</p>\n\n\n\n<p class=\"cag-ozel-text\" style=\"margin-top:-6px;\">Özel ölçü talebiniz varsa aşağıdaki bağlantıları kullanarak bizimle iletişime geçebilirsiniz.</p>\n\n\n\n<p class=\"cag-ozel-text\" style=\"margin-top:-6px;\">Bu ürünler size özel hazırlandığı için iade kabul edilmez.</p>\n\n\n\n<div class=\"cag-ozel-actions\"><a class=\"cag-btn cag-btn-outline\" href=\"/hali-olcu-alma-rehberi\"><span class=\"cag-btn-icon\"> <img alt=\"Ölçü alma\" src=\"https://static.ticimax.cloud/72848/uploads/images/web-images-for-pages/ruler.svg\" style=\"width:14px;height:14px;display:block;\" /> </span> <span>Ölçü Alma Rehberi</span> </a> <a class=\"cag-btn cag-btn-primary\" href=\"https://wa.me/905424827186\" id=\"cag-wa-btn\" rel=\"noopener noreferrer\" target=\"_blank\"> <span aria-hidden=\"true\" class=\"cag-btn-icon-whatsapp\"></span> <span>Özel Ölçü İçin Bize Ulaşın</span> </a></div>\n\n</div>\n\n<script>\n\n(function() {\n\n  var rawName = '';\n\n  var elName = document.querySelector(\n\n    '.ProductDetailMain .RightDetail h1, #ProductDetailMain h1, .urunDetayBaslik, .product-title, h1[itemprop=\"name\"]'\n\n  );\n\n  if (elName && elName.textContent.trim()) {\n\n    rawName = elName.textContent.trim();\n\n  } else {\n\n    rawName = 'ürün';\n\n  }\n\n\n\n  var beforePipe = rawName.split('|')[0].trim();\n\n\n\n  var productTitle = beforePipe;\n\n  var sku = '';\n\n  var dashIndex = beforePipe.lastIndexOf(' - ');\n\n  if (dashIndex !== -1) {\n\n    productTitle = beforePipe.substring(0, dashIndex).trim();\n\n    sku = beforePipe.substring(dashIndex + 3).trim();\n\n  }\n\n\n\n  productTitle = productTitle.replace(/\\s+/g, ' ').trim();\n\n\n\n  var pageUrl = window.location.href;\n\n\n\n  var msg = 'Merhaba, \"' + productTitle + '\"';\n\n  if (sku) {\n\n    msg += ' (' + sku + ')';\n\n  }\n\n  msg += ' ile ilgili bilgi almak istiyorum.\\n\\nÜrün linki: ' + pageUrl;\n\n\n\n  var waBtn = document.getElementById('cag-wa-btn');\n\n  if (waBtn) {\n\n    waBtn.href = 'https://wa.me/905424827186?text=' + encodeURIComponent(msg);\n\n  }\n\n})();\n\n</script>"),
